#!/usr/bin/env python3
"""CTCannabisPoliticalCheck — SINGLE-FILE build (auto-generated by build_single_file.py).

One program, one file. Connecticut Legislature & Municipal Cannabis Conflict-of-
Interest Screening. A screening aid for humans, NOT an automated accusation engine.

Run (LIVE ONLY — never uses synthetic/demo data):
    python3 CTCannabisPoliticalCheck_app.py            # real public sources

Every embedded module/data file is base64-packed below; a meta-path loader serves
the `src.*` package and the data files are materialized into ~/.ct_cannabis_check
(override with $CTCPC_HOME). Edit the original package + re-run build_single_file.py
to regenerate this file."""
from __future__ import annotations

import base64
import importlib.abc
import importlib.util
import os
import sys
from pathlib import Path

# ---------------------------------------------------------------- embedded blobs
_PKGS = ['src', 'src.analyze', 'src.collectors', 'src.normalize', 'src.report', 'src.resolve', 'src.store']
_MODULES = {'src': '', 'src.analyze': '', 'src.analyze.cannabis_terms': '', 'src.analyze.classify': '', 'src.analyze.municipal': '', 'src.analyze.recusals': '', 'src.cli': '', 'src.collectors': '', 'src.collectors.base': '', 'src.collectors.business_registry': '', 'src.collectors.campaign_finance': '', 'src.collectors.dcp_cannabis': '', 'src.collectors.elicense_roster': '', 'src.collectors.ethics_sfi': '', 'src.collectors.legislators_current': '', 'src.collectors.legislators_historical': '', 'src.collectors.live_socrata': '', 'src.collectors.lobbyists': '', 'src.collectors.municipal': '', 'src.collectors.ose_lobbyists': '', 'src.collectors.ownership_network': '', 'src.collectors.seec_finance': '', 'src.collectors.town_attorneys': '', 'src.config': '', 'src.donor_dict': '', 'src.models': '', 'src.municipal': '', 'src.normalize': 'ZnJvbSAubmFtZXMgaW1wb3J0ICgKICAgIE5hbWVQYXJ0cywKICAgIGNhbm9uaWNhbCwKICAgIG5hbWVfdmFyaWFudHMsCiAgICBwYXJzZV9uYW1lLAogICAgc3VybmFtZV9rZXksCikKCl9fYWxsX18gPSBbIk5hbWVQYXJ0cyIsICJjYW5vbmljYWwiLCAibmFtZV92YXJpYW50cyIsICJwYXJzZV9uYW1lIiwgInN1cm5hbWVfa2V5Il0K', 'src.normalize.names': '', 'src.pipeline': '', 'src.report': '', 'src.report.build': '', 'src.resolve': 'ZnJvbSAubWF0Y2hlciBpbXBvcnQgUmVmUmVjb3JkLCBNYXRjaGVyCgpfX2FsbF9fID0gWyJSZWZSZWNvcmQiLCAiTWF0Y2hlciJdCg==', 'src.resolve.cga_votes': '', 'src.resolve.matcher': '', 'src.resolve.relationship': '', 'src.resolve.verified_cache': '', 'src.resolve.voting': '', 'src.resolve.web_search': '', 'src.store': 'ZnJvbSAuZGIgaW1wb3J0IFN0b3JlCgpfX2FsbF9fID0gWyJTdG9yZSJdCg==', 'src.store.db': ''}          # dotted name -> base64 source
_DATA = {'config.yaml': '', 'sources.yaml': '', 'data/known_municipal_findings.json': '', 'data/town_attorney_chains.json': ''}                # relpath -> base64 content


def _decode(b64: str) -> str:
    return base64.b64decode(b64.encode("ascii")).decode("utf-8")


# ---------------------------------------------------------------- working home
HOME = Path(os.environ.get("CTCPC_HOME", Path.home() / ".ct_cannabis_check"))
HOME.mkdir(parents=True, exist_ok=True)
for _rel, _b64 in _DATA.items():
    _p = HOME / _rel
    _p.parent.mkdir(parents=True, exist_ok=True)
    if not _p.exists():                 # never clobber a user edit
        _p.write_text(_decode(_b64), encoding="utf-8")


# ---------------------------------------------------------------- module loader
class _EmbeddedLoader(importlib.abc.MetaPathFinder, importlib.abc.Loader):
    def find_spec(self, name, path=None, target=None):
        if name not in _MODULES:
            return None
        return importlib.util.spec_from_loader(
            name, self, is_package=(name in _PKGS))

    def create_module(self, spec):
        return None

    def exec_module(self, module):
        name = module.__name__
        # Point __file__ at HOME/<path>.py so config.py's
        # ROOT = Path(__file__).resolve().parent.parent resolves to HOME, and every
        # ROOT-relative read (config.yaml, data/, out/, reports/) lands under the
        # materialized home dir. (No synthetic fixtures are bundled — live only.)
        rel = Path(*name.split(".")) / ("__init__.py" if name in _PKGS else "")
        if name not in _PKGS:
            rel = Path(*name.split(".")).with_suffix(".py")
        module.__file__ = str(HOME / rel)
        if name in _PKGS:
            module.__path__ = [str((HOME / Path(*name.split("."))))]
        code = compile(_decode(_MODULES[name]), module.__file__, "exec")
        exec(code, module.__dict__)


sys.meta_path.insert(0, _EmbeddedLoader())


# ---------------------------------------------------------------- launcher
def main(argv=None) -> int:
    import argparse
    from datetime import datetime, timezone
    from src.config import config
    from src.pipeline import Pipeline
    from src.municipal import MunicipalPipeline
    from src.report import finalize_report, DISPLAY_NAME, app_version

    def _log(msg):
        print(f"[{datetime.now(timezone.utc).strftime('%H:%M:%S')}] {msg}")

    ap = argparse.ArgumentParser(prog="CTCannabisPoliticalCheck",
                                 description=f"{DISPLAY_NAME} v{app_version()}")
    ap.add_argument("--refresh-cache", action="store_true")
    ap.add_argument("--no-municipal", action="store_true")
    ap.add_argument("--no-downloads", action="store_true")
    ap.add_argument("--since-year", type=int, default=None)
    args = ap.parse_args(argv)

    # LIVE ONLY. Journalistic investigative tool — real public records, never synthetic
    # data. No offline/fixture mode (the synthetic fixtures are not even bundled).
    cfg = config()
    _log(f"{DISPLAY_NAME} v{app_version()} — LIVE (real sources only; never synthetic) "
         f"[single-file]")
    _log(f"working home: {HOME}")

    result = Pipeline(offline=False, refresh=args.refresh_cache,
                      since_year=args.since_year).run()
    _log(f"legislators: {result.counts['legislators']:,} · cross-referenced "
         f"{result.counts.get('cross_referenced', 0)} · cannabis people "
         f"{result.counts.get('cannabis_persons', 0)}")
    for d in result.legislator_cannabis_leads:
        if d.get("confidence") in ("CONFIRMED", "PROBABLE", "POSSIBLE"):
            _log(f"   [{d['confidence']}] {d['person']} ({d['role']}) ~ "
                 f"{d['cannabis_person']} / {d['cannabis_entity']}")

    municipal = None
    if not args.no_municipal:
        municipal = MunicipalPipeline(offline=False,
                                      refresh=args.refresh_cache).run()

    rep = finalize_report(result, cfg, municipal=municipal,
                          push_to_downloads=not args.no_downloads)
    _log(f"REPORT #{rep['number']} written: {rep['report_pdf']}")
    if rep.get("downloads_pdf"):
        _log(f"copied to Downloads: {rep['downloads_pdf']}")
    _log("Screening aid only — every line item is an UNVERIFIED LEAD until a human "
         "confirms it against the cited primary source. No legal conclusions.")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
